import React, { useState, useRef } from "react";
import MapView from "../components/MapView";
import CameraCapture from "../components/CameraCapture";

function Journey() {

  const [originCoords, setOriginCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [vehicleImage, setVehicleImage] = useState(null);
  const [destination, setDestination] = useState("");
  const [journeyStarted, setJourneyStarted] = useState(false);
  const [safetyStatus, setSafetyStatus] = useState("SAFE");
  const [info, setInfo] = useState(null);
  const [tracking, setTracking] = useState(false);

  const watchId = useRef(null);
  const lastLat = useRef(null);
  const lastLon = useRef(null);
  const stopTimer = useRef(null);

  const handleCapture = (image) => setVehicleImage(image);

  /* DISTANCE */
  function getDistance(lat1, lon1, lat2, lon2) {
    const R = 6371;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;

    const a =
      Math.sin(dLat / 2) ** 2 +
      Math.cos(lat1 * Math.PI / 180) *
      Math.cos(lat2 * Math.PI / 180) *
      Math.sin(dLon / 2) ** 2;

    return R * (2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)));
  }

  /* SOS */
  const triggerEmergency = () => {
    alert("🚨 Emergency triggered!");
    window.location.href = "tel:112";
  };

  /* START TRACKING */
  const startTracking = () => {

    if (!navigator.geolocation) {
      alert("Geolocation not supported");
      return;
    }

    setTracking(true);

    watchId.current = navigator.geolocation.watchPosition(

      (pos) => {

        const lat = pos.coords.latitude;
        const lon = pos.coords.longitude;

        setOriginCoords({ lat, lon });

        /* DISTANCE + TIME */
        if (destinationCoords) {
          const dist = getDistance(lat, lon, destinationCoords.lat, destinationCoords.lon);

          setInfo({
            distance: dist.toFixed(2),
            time: (dist / 40 * 60).toFixed(0) // avg 40 km/h
          });
        }

        /* STOP DETECTION */
        if (lastLat.current !== null) {
          const movement = Math.sqrt(
            Math.pow(lat - lastLat.current, 2) +
            Math.pow(lon - lastLon.current, 2)
          );

          if (movement < 0.0001) {
            if (!stopTimer.current) {
              stopTimer.current = setTimeout(() => {
                setSafetyStatus("ALERT");
                alert("🚨 User stopped for long!");
              }, 120000);
            }
          } else {
            clearTimeout(stopTimer.current);
            stopTimer.current = null;
            setSafetyStatus("SAFE");
          }
        }

        lastLat.current = lat;
        lastLon.current = lon;
      },

      (error) => {
        console.log(error);

        if (error.code === 1) {
          alert("Permission denied. Allow location.");
        } else if (error.code === 2) {
          alert("Location unavailable. Turn on GPS.");
        } else {
          alert("Location timeout.");
        }
      },

      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0
      }
    );
  };

  /* STOP TRACKING */
  const stopTracking = () => {
    if (watchId.current) {
      navigator.geolocation.clearWatch(watchId.current);
      setTracking(false);
    }
  };

  /* DESTINATION SEARCH */
  const setDestinationFunc = async () => {

    if (!destination) {
      alert("Enter destination");
      return;
    }

    const res = await fetch(
      `https://nominatim.openstreetmap.org/search?format=json&q=${destination}`
    );

    const data = await res.json();

    if (data.length > 0) {
      setDestinationCoords({
        lat: parseFloat(data[0].lat),
        lon: parseFloat(data[0].lon),
      });
      setJourneyStarted(true);
    } else {
      alert("Location not found");
    }
  };

  return (

    <div className="container">

      {/* STATUS */}
      <div className={`safety-indicator ${safetyStatus}`}>
        {safetyStatus === "SAFE" ? "🟢 Safe Journey" : "🚨 Emergency"}
      </div>

      <div className="card">

        <h2>Journey Details</h2>

        <input
          type="text"
          placeholder="Enter Destination"
          value={destination}
          onChange={(e) => setDestination(e.target.value)}
          disabled={journeyStarted}
        />

        <button onClick={setDestinationFunc}>
          Set Destination
        </button>

        <button onClick={startTracking} disabled={tracking}>
          {tracking ? "Tracking..." : "Start Tracking"}
        </button>

        <button onClick={stopTracking}>
          Stop Tracking
        </button>

        {info && (
          <p>
            📏 Distance: {info.distance} km <br />
            ⏱ Time: {info.time} mins
          </p>
        )}

        {/* CAMERA */}
        <CameraCapture onCapture={handleCapture} />

        {vehicleImage && (
          <div>
            <h4>Captured Vehicle</h4>
            <img src={vehicleImage} alt="vehicle" style={{ width: "100%" }} />
          </div>
        )}

      </div>

      {/* MAP */}
      <MapView
        origin={originCoords}
        destination={destinationCoords}
        setInfo={setInfo}
      />

      {/* SOS */}
      <button className="sos-btn" onClick={triggerEmergency}>
        🚨 SOS
      </button>

    </div>
  );
}

export default Journey;
